"""
Reads config.json and data.csv, generates a SQL schema and INSERT statements,
saves the result to schema.sql, and prints it to stdout.
"""

import csv
import json
import re
import sys
from pathlib import Path


# ── helpers ──────────────────────────────────────────────────────────────────

def infer_sql_type(values: list[str]) -> str:
    """
    Infer the SQL column type from a list of raw string values.
    Precedence: INTEGER → REAL → TEXT
    NULL / empty strings are skipped so they don't poison the type.
    """
    best = "INTEGER"
    for raw in values:
        stripped = raw.strip()
        if stripped == "" or stripped.upper() == "NULL":
            continue
        if best == "INTEGER":
            try:
                int(stripped)
                continue
            except ValueError:
                best = "REAL"
        if best == "REAL":
            try:
                float(stripped)
                continue
            except ValueError:
                best = "TEXT"
                break
    return best


def quote_identifier(name: str) -> str:
    """Wrap an identifier in double-quotes, escaping any embedded double-quotes."""
    return '"' + name.replace('"', '""') + '"'


def escape_sql_string(value: str) -> str:
    """Escape a string value for use inside single-quoted SQL literals."""
    return value.replace("'", "''")


def sql_literal(value: str, col_type: str) -> str:
    """
    Return the SQL literal representation of *value* given the column's type.
    Empty strings and 'null' (case-insensitive) become NULL.
    """
    stripped = value.strip()
    if stripped == "" or stripped.upper() == "NULL":
        return "NULL"
    if col_type == "INTEGER":
        try:
            return str(int(stripped))
        except ValueError:
            pass
    if col_type == "REAL":
        try:
            return str(float(stripped))
        except ValueError:
            pass
    # Fall back to a quoted string
    return f"'{escape_sql_string(stripped)}'"


# ── main ─────────────────────────────────────────────────────────────────────

def main() -> None:
    config_path = Path("config.json")
    data_path   = Path("data.csv")
    output_path = Path("schema.sql")

    # ── load config ──────────────────────────────────────────────────────────
    if not config_path.exists():
        sys.exit(f"Error: '{config_path}' not found.")

    with config_path.open(encoding="utf-8") as fh:
        config = json.load(fh)

    try:
        table_name = config["database"]["name"]
    except (KeyError, TypeError):
        sys.exit("Error: config.json must contain a 'database.name' key.")

    if not re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", table_name):
        # Still usable — we'll quote it; just warn.
        print(
            f"Warning: table name '{table_name}' contains special characters "
            "and will be double-quoted.",
            file=sys.stderr,
        )

    # ── load CSV ─────────────────────────────────────────────────────────────
    if not data_path.exists():
        sys.exit(f"Error: '{data_path}' not found.")

    with data_path.open(newline="", encoding="utf-8") as fh:
        reader  = csv.DictReader(fh)
        if reader.fieldnames is None:
            sys.exit("Error: data.csv appears to be empty.")
        columns = list(reader.fieldnames)
        rows    = list(reader)

    if not columns:
        sys.exit("Error: data.csv has no columns.")

    # ── infer column types ───────────────────────────────────────────────────
    col_values = {col: [row[col] for row in rows] for col in columns}
    col_types  = {col: infer_sql_type(vals) for col, vals in col_values.items()}

    # ── build SQL ────────────────────────────────────────────────────────────
    tbl = quote_identifier(table_name)

    # CREATE TABLE
    col_defs = ",\n".join(
        f"    {quote_identifier(col)} {col_types[col]}"
        for col in columns
    )
    create_stmt = f"CREATE TABLE IF NOT EXISTS {tbl} (\n{col_defs}\n);"

    # INSERT statements
    insert_lines: list[str] = []
    col_list = ", ".join(quote_identifier(c) for c in columns)
    for row in rows:
        values = ", ".join(sql_literal(row[col], col_types[col]) for col in columns)
        insert_lines.append(f"INSERT INTO {tbl} ({col_list}) VALUES ({values});")

    # Assemble full output
    parts = [
        f"-- Generated from '{data_path}' with table name from '{config_path}'",
        "",
        create_stmt,
    ]
    if insert_lines:
        parts += ["", "-- Data"] + insert_lines

    sql_output = "\n".join(parts) + "\n"

    # ── write & print ────────────────────────────────────────────────────────
    output_path.write_text(sql_output, encoding="utf-8")
    print(sql_output)
    print(f"-- Saved to '{output_path}'", file=sys.stderr)


if __name__ == "__main__":
    main()

